CODE_EXAMPLE:
// Before
class Account {
  int interestRate() {
    return type == GOLD ? 10 : 5;
  }
}

// After
class Account {
  AccountType accountType;
  int interestRate() {
    return accountType.interestRate();
  }
}

interface AccountType {
  int interestRate();
}

UNIT_TEST_EXAMPLE:
@Test
public void testTypeCodeState() {
  Account account = new Account(new GoldAccount());
  assertEquals(10, account.interestRate());
}
